async function importDepenses() {
  console.log(`\n📊 Import de ${data.length} dépenses dans Supabase...\n`)

  let success = 0
  let errors = 0
  const batchSize = 50

  for (let i = 0; i < data.length; i += batchSize) {
    const batch = data.slice(i, i + batchSize)
    const { error } = await supabase.from('transactions').insert(batch)
    
    if (error) {
      errors += batch.length
      console.error('❌ Batch', i, error.message)
    } else {
      success += batch.length
      console.log(`✅ ${success}/${data.length} dépenses importées...`)
    }
  }

  console.log(`\n🎉 Import terminé !`)
  console.log(`✅ ${success} dépenses importées`)
  if (errors > 0) console.log(`❌ ${errors} erreurs`)

  const { count } = await supabase.from('transactions').select('*', { count: 'exact', head: true })
  console.log(`\n📈 Total dans Supabase : ${count} transactions`)
}

importDepenses()
